tasks.command:
echo "/* Admin Calendar Grid */
.calendar-grid {
    display: grid;
    grid-template-columns: 80px repeat(3, 1fr);
    gap: 1px;
    background-color: #334155; /* Cor das linhas da grelha */
    border: 1px solid #334155;
}

.calendar-header-cell {
    background-color: #1e293b;
    padding: 10px;
}

.calendar-time-cell {
    background-color: #1e293b;
    color: #94a3b8;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.85rem;
    padding: 10px;
}

.calendar-slot {
    background-color: #0f172a;
    min-height: 60px;
    position: relative;
    transition: background-color 0.2s;
    padding: 5px;
}

.calendar-slot:hover {
    background-color: #1e293b;
}

.calendar-booking {
    font-size: 0.75rem;
    padding: 4px;
    border-radius: 4px;
    color: white;
    height: 100%;
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
    cursor: pointer;
}

.bg-slot-pending { background-color: rgba(234, 179, 8, 0.2); border-left: 3px solid #facc15; }
.bg-slot-approved { background-color: rgba(34, 197, 94, 0.2); border-left: 3px solid #4ade80; }
.bg-slot-rejected { background-color: rgba(239, 68, 68, 0.2); border-left: 3px solid #f87171; }
" >> c:\Users\ESRP\Desktop\Pap\css\style.css

